def _split_sentence(sentence, n_splits=8):
    """Split a sentence at roughly evenly-spaced word boundaries."""
    words = sentence.split()
    if len(words) < 4:
        return []
    pairs = []
    step = max(1, (len(words) - 2) // (n_splits - 1))
    positions = sorted(set(
        [max(2, min(i, len(words) - 2)) for i in range(2, len(words) - 1, step)]
    ))
    for pos in positions[:n_splits]:
        first = " ".join(words[:pos])
        second = " ".join(words[pos:])
        pairs.append((first, second))
    return pairs


def _gen_mid_sentence():
    cases = []
    for si, sent in enumerate(_FULL_SENTENCES):
        for pi, (first, second) in enumerate(_split_sentence(sent)):
            cases.append((first, second, 0.5, f"midsent_{si:03d}_p{pi}"))
    return cases


LIKELY_MID_SENTENCE = _gen_mid_sentence()


