# ═══════════════════════════════════════════════════════════════════════
#  Parametrized tests
# ═══════════════════════════════════════════════════════════════════════


@pytest.mark.integration
@pytest.mark.continuation
@pytest.mark.parametrize(
    "first,second,min_score,test_id",
    LIKELY_CASES,
    ids=[c[3] for c in LIKELY_CASES],
)
def test_likely_continuation(first, second, min_score, test_id, api):
    """Text fragments that naturally continue from one another."""
    body = continuation_check(api, first, second)
    assert body["result"] == "likely_continuation", (
        f"[{test_id}] Expected likely_continuation: "
        f"'{first[:40]}...' -> '{second[:40]}...'"
    )
    assert body["score"] >= min_score, (
        f"[{test_id}] Score {body['score']} < min {min_score}"
    )


@pytest.mark.integration
@pytest.mark.continuation
@pytest.mark.parametrize(
    "first,second,max_score,test_id",
    UNLIKELY_CASES,
    ids=[c[3] for c in UNLIKELY_CASES],
)
def test_unlikely_continuation(first, second, max_score, test_id, api):
    """Text fragments that do NOT naturally continue from one another."""
    body = continuation_check(api, first, second)
    assert body["result"] == "unlikely_continuation", (
        f"[{test_id}] Expected unlikely_continuation: "
        f"'{first[:40]}...' -> '{second[:40]}...'"
    )
    assert body["score"] <= max_score, (
        f"[{test_id}] Score {body['score']} > max {max_score}"
    )
